package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    public void testParse_ReturnsCSVParserInstance() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        CSVParser mockParser = mock(CSVParser.class);

        CSVFormat spyFormat = spy(format);

        doReturn(mockParser).when(spyFormat).parse(any(Reader.class));

        CSVParser parser = spyFormat.parse(mockReader);

        assertNotNull(parser);
        assertTrue(parser instanceof CSVParser);
        assertSame(mockParser, parser);
    }

    @Test
    public void testParse_NullReader_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }

}
